#include <iostream>\n#include <vector>\n#include <algorithm>\n#include <cstdint>\n\nclass Graph {\n public:\n  Graph(int n, const std::vector<std::pair<int, int>>& edges) {\n    table_.resize(n);\n    visited_.resize(n, false);\n    colors_.resize(n, 0);\n    Build(edges);\n  }\n\n  bool IsTwoColor() {\n    if (!Dfs(0, 1)) {\n      return false;\n    }\n    for (size_t i = 1; i < visited_.size(); i++) {\n      if (!visited_[i] && !Dfs(i, 1)) {\n        return false;\n      }\n    }\n    return true;\n  }\n\n private:\n  void Build(const std::vector<std::pair<int, int>>& edges) {\n    for (const std::pair<int, int>& pair : edges) {\n      int i = pair.first - 1;\n      int j = pair.second - 1;\n      table_[i].push_back(j);\n      table_[j].push_back(i);\n    }\n  }\n\n  bool Dfs(size_t start, int color) {\n    visited_[start] = true;\n    colors_[start] = color;\n    const std::vector<int>& children = table_[start];\n    for (auto i : children) {\n      if (colors_[i] == color || (colors_[i] == 0 && !Dfs(i, -color))) {\n        return false;\n      }\n    }\n    return true;\n  }\n\n  std::vector<std::vector<int>> table_;\n  std::vector<bool> visited_;\n  std::vector<int> colors_;\n};\n\nint main() {\n  int n = 0;\n  int m = 0;\n  std::cin >> n >> m;\n  std::vector<std::pair<int, int>> edges(m);\n  for (int it = 0; it < m; it++) {\n    int i = 0;\n    int j = 0;\n    std::cin >> i >> j;\n    edges[it] = {i, j};\n  }\n\n  Graph graph(n, edges);\n\n  if (graph.IsTwoColor()) {\n    std::cout << \"YES\" << std::endl;\n  } else {\n    std::cout << \"NO\" << std::endl;\n  }\n  return 0;\n}